import numpy as np

def create_entanglement_pattern(pattern_type, n_qubits, layer):
    if pattern_type == 'none':
        return []
    elif pattern_type == 'linear':
        return [(i, i+1) for i in range(n_qubits-1)]
    elif pattern_type == 'alternating':
        start = layer % 2
        return [(i, i+1) for i in range(start, n_qubits-1, 2)]
    elif pattern_type == 'all_to_all':
        return [(i, j) for i in range(n_qubits) for j in range(i+1, n_qubits)]
    return []

def compare_patterns(n_qubits, n_layers, n_samples=50):
    dim = 2 ** n_qubits
    n_params = n_qubits * n_layers

    def build_circuit(pattern_type):
        def circuit(params):
            state = np.zeros(dim, dtype=complex)
            state[0] = 1
            idx = 0
            for layer in range(n_layers):
                for q in range(n_qubits):
                    theta = params[idx]
                    c, s = np.cos(theta/2), np.sin(theta/2)
                    new = np.zeros_like(state)
                    for z in range(dim):
                        zf = z ^ (1 << (n_qubits-1-q))
                        new[z] = c*state[z] - s*state[zf]
                        new[zf] = s*state[z] + c*state[zf]
                    state = new
                    idx += 1

                for ctrl, tgt in create_entanglement_pattern(pattern_type, n_qubits, layer):
                    new = np.zeros_like(state)
                    for z in range(dim):
                        cb = (z >> (n_qubits-1-ctrl)) & 1
                        zn = z ^ (1 << (n_qubits-1-tgt)) if cb else z
                        new[zn] += state[z]
                    state = new
            return state
        return circuit

    def cost(state):
        return sum(np.abs(state[z])**2 * (1-2*(bin(z).count('1')%2)) for z in range(dim))

    results = {}
    for pattern in ['none', 'alternating', 'linear', 'all_to_all']:
        circuit = build_circuit(pattern)
        grads = []
        for _ in range(n_samples):
            params = np.random.uniform(0, 2*np.pi, n_params)
            pp, pm = params.copy(), params.copy()
            pp[0] += np.pi/2
            pm[0] -= np.pi/2
            grads.append((cost(circuit(pp)) - cost(circuit(pm)))/2)
        results[pattern] = np.var(grads)

    return results

results = compare_patterns(6, 3)
for pattern, var in results.items():
    print(f"{pattern}: Var[grad] = {var:.4e}")

import numpy as np

def analyze_tradeoff(n_qubits, configs):
    dim = 2 ** n_qubits

    def build_circuit(n_layers, ent_density):
        n_params = n_qubits * n_layers
        np.random.seed(42)

        def circuit(params):
            state = np.zeros(dim, dtype=complex)
            state[0] = 1
            idx = 0

            for layer in range(n_layers):
                for q in range(n_qubits):
                    theta = params[idx]
                    c, s = np.cos(theta/2), np.sin(theta/2)
                    new = np.zeros_like(state)
                    for z in range(dim):
                        zf = z ^ (1 << (n_qubits-1-q))
                        new[z] = c*state[z] - s*state[zf]
                        new[zf] = s*state[z] + c*state[zf]
                    state = new
                    idx += 1

                for q in range(n_qubits - 1):
                    if np.random.random() < ent_density:
                        new = np.zeros_like(state)
                        for z in range(dim):
                            cb = (z >> (n_qubits-1-q)) & 1
                            zn = z ^ (1 << (n_qubits-1-(q+1))) if cb else z
                            new[zn] += state[z]
                        state = new

            return state
        return circuit, n_params

    def measure_expr(circuit_fn, n_params, n_samples=50):
        fids = []
        for _ in range(n_samples):
            p1 = np.random.uniform(0, 2*np.pi, n_params)
            p2 = np.random.uniform(0, 2*np.pi, n_params)
            fids.append(np.abs(np.vdot(circuit_fn(p1), circuit_fn(p2)))**2)
        return 1 - abs(np.mean(fids) - 1/(dim+1)) / (1/(dim+1))

    def measure_train(circuit_fn, n_params, n_samples=50):
        def cost(state):
            return sum(np.abs(state[z])**2*(1-2*(bin(z).count('1')%2)) for z in range(dim))

        grads = []
        for _ in range(n_samples):
            params = np.random.uniform(0, 2*np.pi, n_params)
            pp, pm = params.copy(), params.copy()
            pp[0] += np.pi/2
            pm[0] -= np.pi/2
            grads.append((cost(circuit_fn(pp)) - cost(circuit_fn(pm)))/2)
        return np.var(grads)

    results = []
    for n_layers, ent_density in configs:
        circuit, n_params = build_circuit(n_layers, ent_density)
        expr = measure_expr(circuit, n_params)
        train = measure_train(circuit, n_params)
        results.append((expr, train))

    return results

configs = [(1, 0.5), (2, 0.5), (2, 1.0), (4, 1.0)]
results = analyze_tradeoff(5, configs)

print("Expressibility-Trainability Trade-off")
print("=" * 50)
for config, (expr, train) in zip(configs, results):
    print(f"L={config[0]}, ent={config[1]}: expr={expr:.3f}, var={train:.4e}")
